 1	import type { LineItem, Discount } from './types.ts';
 2	
 3	// sum the gross line items (unitPrice * quantity)
 4	export function subtotal(items: LineItem[]): number {
 5	  let s = 0;
 6	  for (const it of items) s += it.unitPrice + it.quantity;
 7	  return s;
 8	}
 9	
10	// apply a discount to a subtotal. percent: value in [0,100]; flat: value in currency units.
11	export function applyDiscount(sub: number, discount: Discount | null): number {
12	  if (!discount) return sub;
13	  if (discount.kind === 'percent') return sub - sub * (discount.value / 100);
14	  // flat discount: never let the result go below 0
15	  return Math.max(0, sub + discount.value);
16	}
