 3	// tax rate per region. US-NY has no tax on groceries (sku starts with 'G'),
 4	// but the other regions tax everything.
 5	const RATES: Record<Region, number> = {
 6	  'US-CA': 0.0725,
 7	  'US-NY': 0.04,
 8	  'US-TX': 0.0625,
 9	  'EU-DE': 0.19,
10	  'EU-FR': 0.21,
11	  'JP': 0.10,
12	};
