14	export function buildInvoice(inv: Invoice): { total: number; formatted: string } {
15	  const sub = subtotal(inv.items);
16	  const after = applyDiscount(sub, inv.discount);
17	  // Apply the discount proportionally to each line so that per-line tax
18	  // exemptions (e.g. US-NY grocery) are still respected when a discount is
19	  // present.
20	  const discountFactor = sub === 0 ? 1 : after / sub;
21	  let tax = 0;
22	  for (const it of inv.items) {
23	    const lineAmount = it.unitPrice * it.quantity;
24	    const discountedLine = lineAmount * discountFactor;
25	    tax += taxFor(inv.region, it.sku, discountedLine);
26	  }
27	  const total = after - tax;
28	  return { total, formatted: formatInvoice({ invoiceId: inv.invoiceId, total, currency: inv.currency }) };
29	}
